def _load_embedded_weights(nnet):
    """Decode embedded weights and load into the network."""
    raw = gzip.decompress(base64.b64decode(''.join(_MODEL_BLOB)))
    half_state = torch.load(io.BytesIO(raw), weights_only=True, map_location='cpu')
    state = {k: v.float() for k, v in half_state.items()}
    nnet.model.load_state_dict(state)



# MCTS
_SIMULATION_NUM = 200
_C_PUCT = 1.5
_DIRICHLET_ALPHA = 0.3
_DIRICHLET_EPSILON = 0.25

# Network (must match checkpoint)
_CONV_FILTERS = 64
_CONV_KERNEL = (3, 3)
_RESIDUAL_BLOCK_NUM = 4

# ============================================================================
# Neural Network  (exact port from alphazero/nnet.py)
# ============================================================================

class _ResidualBlock(nn.Module):
    def __init__(self, filters, kernel_size):
        super().__init__()
        p = kernel_size[0] // 2
        self.conv1 = nn.Conv2d(filters, filters, kernel_size, padding=p)
        self.bn1 = nn.BatchNorm2d(filters)
        self.conv2 = nn.Conv2d(filters, filters, kernel_size, padding=p)
        self.bn2 = nn.BatchNorm2d(filters)

    def forward(self, x):
        r = x
        out = torch.relu(self.bn1(self.conv1(x)))
        out = self.bn2(self.conv2(out))
        return torch.relu(out + r)


class _AlphaZeroModel(nn.Module):
    def __init__(self, rows, cols, conv_filters, conv_kernel, res_blocks):
        super().__init__()
        p = conv_kernel[0] // 2
        self.conv_init = nn.Conv2d(2, conv_filters, conv_kernel, padding=p)
        self.bn_init = nn.BatchNorm2d(conv_filters)
        self.res_blocks = nn.Sequential(
            *[_ResidualBlock(conv_filters, conv_kernel) for _ in range(res_blocks)]
        )
        self.policy_conv = nn.Conv2d(conv_filters, 2, 1)
        self.policy_bn = nn.BatchNorm2d(2)
        self.policy_fc = nn.Linear(2 * rows * cols, rows * cols)

        self.value_conv = nn.Conv2d(conv_filters, 1, 1)
        self.value_bn = nn.BatchNorm2d(1)
        self.value_fc1 = nn.Linear(rows * cols, 256)
        self.value_fc2 = nn.Linear(256, 1)

    def forward(self, x):
        h = torch.relu(self.bn_init(self.conv_init(x)))
        h = self.res_blocks(h)
        p = torch.relu(self.policy_bn(self.policy_conv(h)))
        p = torch.flatten(p, 1)
        p = self.policy_fc(p)
        v = torch.relu(self.value_bn(self.value_conv(h)))
        v = torch.flatten(v, 1)
        v = torch.relu(self.value_fc1(v))
        v = torch.tanh(self.value_fc2(v))
        return p, v


class _NNet:
    """Inference wrapper: load checkpoint, fast JIT predict."""

    def __init__(self, rows, cols):
        self.rows = rows
        self.cols = cols
        self.model = _AlphaZeroModel(
            rows, cols, _CONV_FILTERS, _CONV_KERNEL, _RESIDUAL_BLOCK_NUM,
        ).to(memory_format=torch.channels_last)
        self._buf = torch.empty(1, 2, rows, cols, memory_format=torch.channels_last)
        self._frozen = None

    def load_checkpoint(self, checkpoint_file):
        ckpt = torch.load(checkpoint_file, weights_only=True, map_location="cpu")
        self.model.load_state_dict(ckpt["model"])
        self._frozen = None

    def _build_frozen(self):
        self.model.eval()
        example = torch.randn(1, 2, self.rows, self.cols).to(
            memory_format=torch.channels_last
        )
        traced = torch.jit.trace(self.model, example)
        self._frozen = torch.jit.optimize_for_inference(traced)

    def predict(self, canonical_board):
        """*canonical_board*: np.ndarray (rows, cols, 2). Returns (probs, value)."""
        if self._frozen is None:
            self._build_frozen()
        self._buf[0] = torch.from_numpy(canonical_board).permute(2, 0, 1)
        with torch.inference_mode():
            logits, v = self._frozen(self._buf)
            probs = torch.softmax(logits, dim=1)
        return probs[0].cpu().numpy(), v[0, 0].cpu().numpy()


# ============================================================================
# Game logic  (exact port from connect4/game.py)
# ============================================================================

class _ChessType:
    BLACK = "B"
    WHITE = "W"


class _ConnectGame:
    """Connect-4 engine with SGF-like board representation.

    Board is a string e.g. ``"B[50];W[40];B[41]"`` where:
    - B/W = Black (P1) / White (P2)
    - [xy] = hex-encoded row,col
    - ; separates moves in order

    Matches ``alphazero.game.Game`` API exactly.
    """

    DRAW = "draw"

    def __init__(self, rows=6, columns=7, n_in_row=4):
        self.rows = rows
        self.columns = columns
        self.n_in_row = n_in_row
        self._total = rows * columns
        self._directions = ((1, 0), (0, 1), (1, 1), (1, -1))
        self._semicolon = ";"

    # ---- Game API ----

    def get_initial_state(self):
        return "", _ChessType.BLACK

    def next_state(self, board, action, player):
        col = action % self.columns
        heights = self._column_heights(board)
        if heights[col] >= self.rows:
            raise ValueError(f"Column {col} is full")
        row = self.rows - heights[col] - 1
        stone = "%s[%x%x]" % (player, row, col)
        nxt = self.next_player(player)
        if board:
            return board + self._semicolon + stone, nxt
        return stone, nxt

    def is_terminal_state(self, board, action, player):
        if not board:
            return None

        rows, cols, n = self.rows, self.columns, self.n_in_row

        player_positions = set()
        total_stones = 0
        for stone in board.split(self._semicolon):
            if not stone:
                continue
            x = int(stone[2], 16)
            y = int(stone[3], 16)
            if 0 <= x < rows and 0 <= y < cols:
                total_stones += 1
                if stone[0] == player:
                    player_positions.add((x, y))

        ax, ay = divmod(action, cols)
        if (ax, ay) not in player_positions:
            heights = self._column_heights(board)
            ay = action % cols
            ax = self.rows - heights[ay]

        has_stone = player_positions.__contains__
        for dx, dy in self._directions:
            count = 1
            x, y = ax + dx, ay + dy
            while 0 <= x < rows and 0 <= y < cols and has_stone((x, y)):
                count += 1
                x += dx
                y += dy
            x, y = ax - dx, ay - dy
            while 0 <= x < rows and 0 <= y < cols and has_stone((x, y)):
                count += 1
                x -= dx
                y -= dy
            if count >= n:
                return player

        if total_stones == self._total:
            return _ConnectGame.DRAW
        return None

    def available_actions(self, board):
        heights = self._column_heights(board)
        actions = []
        for col in range(self.columns):
            if heights[col] < self.rows:
                row = self.rows - heights[col] - 1
                actions.append(row * self.columns + col)
        return actions

    def get_canonical_form(self, board, player):
        rows, cols = self.rows, self.columns
        feature = np.zeros((rows, cols, 2), dtype=np.float32)
        if board:
            opponent = self.next_player(player)
            for stone in board.split(self._semicolon):
                if not stone:
                    continue
                color = stone[0]
                x = int(stone[2], 16)
                y = int(stone[3], 16)
                if color == player:
                    feature[x, y, 0] = 1.0
                elif color == opponent:
                    feature[x, y, 1] = 1.0
        return feature

    def compute_reward(self, winner, player):
        if winner == _ConnectGame.DRAW:
            return 0.0
        return 1.0 if winner == player else -1.0

    # ---- Helpers ----

    @staticmethod
    def next_player(player):
        return _ChessType.BLACK if player == _ChessType.WHITE else _ChessType.WHITE

    def _column_heights(self, board):
        heights = [0] * self.columns
        if not board:
            return heights
        for stone in board.split(self._semicolon):
            if stone:
                heights[int(stone[3], 16)] += 1
        return heights


# ============================================================================
# MCTS  (exact port from alphazero/mcts.py)
# ============================================================================

class _MCTS:
    """AlphaZero MCTS with PUCT selection."""

    def __init__(self, nnet, game, sim_num, c_puct,
                 dirichlet_alpha, dirichlet_epsilon):
        self.nnet = nnet
        self.game = game
        self.sim_num = sim_num
        self.c_puct = c_puct
        self.dirichlet_alpha = dirichlet_alpha
        self.dirichlet_epsilon = dirichlet_epsilon

        self.visit_count = {}
        self.mean_action_value = {}
        self.prior_probability = {}
        self.terminal_state = {}
        self.total_visit_count = {}
        self.available_actions = {}

    def simulate(self, board, player, add_root_noise=False):
        if add_root_noise:
            self._add_root_dirichlet_noise(board, player)
        for _ in range(self.sim_num):
            self.search(board, player)
        return (
            np.copy(self.available_actions[board]),
            np.copy(self.visit_count[board]),
        )

    def _add_root_dirichlet_noise(self, board, player):
        if board not in self.prior_probability:
            self._expand(board, player)
        priors = self.prior_probability[board]
        if len(priors) == 0:
            return
        noise = np.random.dirichlet(
            self.dirichlet_alpha * np.ones(len(priors))
        )
        self.prior_probability[board] = (
            (1.0 - self.dirichlet_epsilon) * priors
            + self.dirichlet_epsilon * noise
        )

    def search(self, board, player):
        if board not in self.prior_probability:
            return -self._expand(board, player)
        idx = self._select(board)
        action = self.available_actions[board][idx]
        next_board, next_player = self.game.next_state(board, action, player)
        if next_board not in self.terminal_state:
            self.terminal_state[next_board] = self.game.is_terminal_state(
                next_board, action, player
            )
        if self.terminal_state[next_board] is not None:
            value = self.game.compute_reward(
                self.terminal_state[next_board], player
            )
        else:
            value = self.search(next_board, next_player)
        self._backup(board, idx, value)
        return -value

    def _select(self, board):
        u = (
            self.c_puct
            * self.prior_probability[board]
            * np.sqrt(self.total_visit_count[board])
            / (1.0 + self.visit_count[board])
        )
        return int(np.argmax(self.mean_action_value[board] + u))

    def _backup(self, board, idx, value):
        n = self.visit_count[board][idx]
        q = self.mean_action_value[board][idx]
        self.mean_action_value[board][idx] = (q * n + value) / (n + 1.0)
        self.visit_count[board][idx] += 1
        self.total_visit_count[board] += 1

    def _expand(self, board, player):
        canonical_board = self.game.get_canonical_form(board, player)
        proba, value = self.nnet.predict(canonical_board)
        actions = self.game.available_actions(board)
        self.available_actions[board] = actions
        if len(actions) == 0:
            self.prior_probability[board] = np.array([])
            self.total_visit_count[board] = 1
            self.mean_action_value[board] = np.zeros(0)
            self.visit_count[board] = np.zeros(0)
            return value
        self.prior_probability[board] = proba[actions] / np.sum(proba[actions])
        self.total_visit_count[board] = 1
        self.mean_action_value[board] = np.zeros(len(actions))
        self.visit_count[board] = np.zeros(len(actions))
        return value


# ============================================================================
# Observation conversion  (Kaggle → SGF board string)
# ============================================================================

def _obs_to_board(observation, configuration):
    """Kaggle observation → SGF board string ``"B[50];W[41]"``."""
    rows, cols = configuration.rows, configuration.columns
    flat = observation.board
    stones = []
    for r in range(rows):
        for c in range(cols):
            val = flat[r * cols + c]
            if val == 1:
                stones.append(f"B[{r:x}{c:x}]")
            elif val == 2:
                stones.append(f"W[{r:x}{c:x}]")
    return ";".join(stones)


# ============================================================================
# Global state
# ============================================================================

_STATE = None  # dict | None  — lazy-initialised, reused across moves


def _init_state(rows, cols, inarow):
    game = _ConnectGame(rows=rows, columns=cols, n_in_row=inarow)
    nnet = _NNet(rows, cols)
    _load_embedded_weights(nnet)
    mcts = _MCTS(
        nnet, game, _SIMULATION_NUM, _C_PUCT,
        _DIRICHLET_ALPHA, _DIRICHLET_EPSILON,
    )
    return {
        "game": game,
        "nnet": nnet,
        "mcts": mcts,
        "config_key": (rows, cols, inarow),
    }


# ============================================================================
# Kaggle entry-point
# ============================================================================

def agent(observation, configuration):
    """Return 0-indexed column to drop a piece into.

    Called once per turn by the Kaggle ConnectX environment.
    """
    global _STATE

    rows = getattr(configuration, "rows", 6)
    cols = getattr(configuration, "columns", 7)
    inarow = getattr(configuration, "inarow", 4)
    key = (rows, cols, inarow)

    if _STATE is None or _STATE["config_key"] != key:
        _STATE = _init_state(rows, cols, inarow)

    game = _STATE["game"]
    mcts = _STATE["mcts"]

    board = _obs_to_board(observation, configuration)
    player = _ChessType.BLACK if observation.mark == 1 else _ChessType.WHITE

    actions, counts = mcts.simulate(board, player, add_root_noise=False)

    if len(actions) == 0:
        for c in range(cols):
            if observation.board[c] == 0:
                return c
        return 0

    best_action = int(actions[np.argmax(counts)])
    return best_action % cols


